let exchangeData = {}, oilData = {}, bondData = {};
const newsList = [];

for (const it of items) {
  const d = it.json;
  if (d.category === 'exchange') exchangeData = d;
  else if (d.category === 'oil') oilData = d;
  else if (d.category === 'bond') bondData = d;
  if (d.news_text) newsList.push(d.news_text);
}

