  return {
    type: 'line',
    data: { labels, datasets },
    options: {
      title: { display: true, text: title, fontSize: 16 },
      legend: { display: true },
      scales: {
        xAxes: [{ ticks: { maxTicksLimit: 10, maxRotation: 45 } }]
      }
    }
