const wtiMatch = text.match(/배럴당\s*([\d,]+\.?\d*)\s*달러에 마감/);
const wti = wtiMatch ? parseFloat(wtiMatch[1].replace(/,/g,'')) : null;

// 뉴스 요약
const lead = text.match(/\((뉴욕|서울)=연합[^)]*\)[^=]+= (.{20,300})\./);
const newsText = lead ? lead[2].trim() : '';

return [{ json: {
  DATE: date,
  'WTI유(NYMEX)': wti,
  news_text: newsText,
  category: 'oil'
}}];

// 채권 기사 파서
const item = $input.first().json;
if (item.category !== 'bond') return [];

const text = (item.content || '').replace(/\s+/g, ' ');

// 날짜
const dateMatch = text.match(/입력 (\d{4})\.(\d{2})\.(\d{2})/);
const date = dateMatch ? dateMatch[1]+'-'+dateMatch[2]+'-'+dateMatch[3] : new Date().toISOString().slice(0,10);

// 3년물
const b3 = text.match(/국고채 3년물 최종호가 수익률은[^%]*?(\d+\.\d+)%/);
// 10년물
const b10 = text.match(/국고채 10년물 금리는[^%]*?(\d+\.\d+)%/);

// 뉴스 요약
const lead = text.match(/\(서울=연합인포맥스\)[^=]+= (.{20,300})\./);
const newsText = lead ? lead[1].trim() : '';

return [{ json: {
  DATE: date,
  '국고채권(3년)': b3 ? parseFloat(b3[1]) : null,
  '국고채권(10년)': b10 ? parseFloat(b10[1]) : null,
  news_text: newsText,
  category: 'bond'
}}];

// 기사 제목으로 category 부여 + URL 추출
const item = $input.first().json;
const title = item.title || '';
const link = item.link || item.url || item.guid || '';

let category = null;
if (title.includes('[서환-마감]')) category = 'exchange';
else if (title.includes('[채권-마감]')) category = 'bond';
else if (title.includes('[뉴욕유가]')) category = 'oil';

if (!category) return [];

return [{ json: { ...item, category, articleUrl: link } }];
